const items = $input.all();
const now = new Date();

// Week boundaries — last 7 days
const weekAgo = new Date(now);
weekAgo.setDate(weekAgo.getDate() - 7);

// Overdue threshold — 14 days ago
const twoWeeksAgo = new Date(now);
twoWeeksAgo.setDate(twoWeeksAgo.getDate() - 14);

// Week label for report title
const weekLabel = weekAgo.toLocaleDateString('en-IN', { 
  day: '2-digit', 
  month: '2-digit', 
  year: 'numeric',
  timeZone: 'Asia/Kolkata'
});

// Source Counts
let sourceCounts = {};

// Status counts
let unread = 0, inProgress = 0, done = 0;

// New this week
let newThisWeek = [];

// Overdue — unread for more than 14 days
let overdueItems = [];

// Tag frequency
let tagCounts = {};

items.forEach(item => {
  const props = item.json;

  const status = props.property_status || "";
  const savedOn = props.property_saved_on?.start 
    ? new Date(props.property_saved_on.start) 
    : null;
  const title = props.property_title || props.name || "Untitled";
  const url = props.property_url || "";
  const tags = props.property_tags || [];
  const source = props.property_source || "";

  // Status counts
  if (status === "Unread") unread++;
  else if (status === "In Progress") inProgress++;
  else if (status === "Done") done++;

  // New this week + source counts — weekly only
  if (savedOn && savedOn >= weekAgo) {
    newThisWeek.push({ title, url, savedOn: savedOn.toLocaleDateString('en-IN', {timeZone: 'Asia/Kolkata'}) });
    if (!sourceCounts[source]) sourceCounts[source] = 0;
    sourceCounts[source]++;
  }

  // Overdue — unread and saved more than 14 days ago
  if (status === "Unread" && savedOn && savedOn < twoWeeksAgo) {
    overdueItems.push({ title, url, savedOn: savedOn.toLocaleDateString('en-IN', {timeZone: 'Asia/Kolkata'}) });
  }

  // Tag frequency
  if (Array.isArray(tags)) {
    tags.forEach(tag => {
      const t = typeof tag === 'string' ? tag : tag?.name || "";
      if (t) tagCounts[t] = (tagCounts[t] || 0) + 1;
    });
  }
});

// Total and completion rate
const total = unread + inProgress + done;
const completionRate = total > 0 ? Math.round((done / total) * 100) : 0;

// Top 5 tags sorted by frequency
const topTags = Object.entries(tagCounts)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 5)
  .map(([tag, count]) => `${tag} (${count})`)
  .join(', ');

// Format overdue details
const overdueDetails = overdueItems
  .slice(0, 10)
  .map(i => `• ${i.title} — saved ${i.savedOn}`)
  .join('\n');

// Format new items details
const newItemsDetails = newThisWeek
  .slice(0, 10)
  .map(i => `• ${i.title} — ${i.savedOn}`)
  .join('\n');

return [{
  json: {
    week_label: weekLabel,
    total: total,
    unread: unread,
    in_progress: inProgress,
    done: done,
    completion_rate: completionRate,
    new_this_week: newThisWeek.length,
    overdue_count: overdueItems.length,
    top_tags: topTags,
    overdue_details: overdueDetails,
    new_items_details: newItemsDetails,
    youtube_count: sourceCounts['YouTube'] || 0,
    instagram_count: sourceCounts['Instagram'] || 0,
    linkedin_count: sourceCounts['LinkedIn'] || 0,
    twitter_count: sourceCounts['Twitter/X'] || 0,
    article_count: sourceCounts['Article'] || 0,
    text_count: sourceCounts['Text'] || 0,
  }
}];

